import React, { useState, useEffect } from "react";
import { getBillsByDate } from "../services/api";

function RecentBills({ billingDate }) {
  const [bills, setBills] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [searchTerm, setSearchTerm] = useState("");

  useEffect(() => {
    fetchBills();
  }, [billingDate]);

  const fetchBills = async () => {
    try {
      setLoading(true);
      const response = await getBillsByDate(billingDate);
      setBills(response || []);
      setError(null);
    } catch (err) {
      console.error("Error fetching bills:", err);
      setError("Failed to fetch bills");
    } finally {
      setLoading(false);
    }
  };

  const filteredBills = bills.filter(
    (bill) =>
      bill.bill_number.toString().includes(searchTerm) ||
      bill.table_no.toLowerCase().includes(searchTerm.toLowerCase()) ||
      bill.grand_total.toString().includes(searchTerm)
  );

  const totalAmount = filteredBills.reduce(
    (sum, bill) => sum + parseFloat(bill.grand_total),
    0
  );

  if (loading) {
    return (
      <div className="recent-bills">
        <h2>Recent Bills</h2>
        <div className="loading">Loading bills...</div>
      </div>
    );
  }

  return (
    <div className="recent-bills">
      <div className="bills-header">
        <h2>Recent Bills</h2>
        <div className="bills-controls">
          <input
            type="text"
            placeholder="Search by bill number, table, or amount..."
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
            className="search-input"
          />
          <button onClick={fetchBills} className="refresh-btn">
            Refresh
          </button>
        </div>
      </div>

      {error && (
        <div className="error-message">
          {error}
          <button onClick={() => setError(null)}>×</button>
        </div>
      )}

      <div className="bills-summary">
        <div className="summary-item">
          <span>Date: {billingDate}</span>
        </div>
        <div className="summary-item">
          <span>Total Bills: {filteredBills.length}</span>
        </div>
        <div className="summary-item">
          <span>Total Amount: ₹{totalAmount.toFixed(2)}</span>
        </div>
      </div>

      {filteredBills.length === 0 ? (
        <div className="no-bills">
          {searchTerm
            ? `No bills found matching "${searchTerm}"`
            : `No bills found for ${billingDate}`}
        </div>
      ) : (
        <div className="bills-table">
          <div className="table-header">
            <span>Bill #</span>
            <span>Table</span>
            <span>Party</span>
            <span>Amount</span>
            <span>Time</span>
            <span>Items</span>
          </div>

          {filteredBills.map((bill) => (
            <div key={bill.id} className="table-row">
              <span className="bill-number">#{bill.bill_number}</span>
              <span>{bill.table_no}</span>
              <span>{bill.party_no}</span>
              <span className="amount">
                ₹{parseFloat(bill.grand_total).toFixed(2)}
              </span>
              <span>{new Date(bill.created_at).toLocaleTimeString()}</span>
              <div className="items-summary">
                {bill.items && bill.items.length > 0 ? (
                  <div className="items-dropdown">
                    <span className="items-count">
                      {bill.items.length} items
                    </span>
                    <div className="items-tooltip">
                      {bill.items.map((item, index) => (
                        <div key={index} className="item-detail">
                          {item.name} x{item.quantity} - ₹
                          {parseFloat(item.line_total).toFixed(2)}
                        </div>
                      ))}
                    </div>
                  </div>
                ) : (
                  <span>No items</span>
                )}
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}

export default RecentBills;
